var lexicalOrder = function(n) {
    const res = [];
    let cur = 1;
    for (let i = 0; i < n; i++) {
        res.push(cur);
        if (cur * 10 <= n) {
            cur *= 10;
        } else {
            while (cur % 10 === 9 || cur + 1 > n) {
                cur = Math.floor(cur / 10);
            }
            cur += 1;
        }
    }
    return res;
};
